# Generated by ollama (mistral)
# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.
# Category: xss

defmodule BlogAppWeb.PostLive do
  use LiveView

  def onChange(_params) do
    connect()
  end

  def onChange_post(params \\ %{}) do
    if params[:id] && is_integer(params[:id]) do
      post = Repo.get!(Post, params[:id])
      post.content = params[:content]
      Repo.update(post)
    end

    push("turbo:refresh", suffix: "posts")
  end

  def render(assigns) do
    ~L"
      <h1>Posts</h1>
      <livewire-posts posts="~{posts|> Map.map(&elem(&1, :post))}" />

      <h2>Create Post</h2>
      <form phx-submit="create_post">
        <textarea name="content" rows="5"></textarea>
        <button type="submit">Save</button>
      </form>
    "
  end

  def create_post(conn, %{"content" => content}) do
    post = Post.new(content: raw(content))
    {:ok, assign(:posts, [post | Enum.reverse(assigns[:posts])])}
  end
end